function solve(grid: number[][]): number {
    const M = grid.length;
    const N = grid[0].length;
    const MAX_XOR = 1024;

    // DP[i][j] stores a boolean array of size MAX_XOR (1024).
    // DP[i][j][k] is true if XOR sum k is achievable when reaching cell (i, j).
    const DP: boolean[][][] = Array(M).fill(0).map(() => 
        Array(N).fill(0).map(() => 
            Array(MAX_XOR).fill(false)
        )
    );

    // Base case (0, 0)
    DP[0][0][grid[0][0]] = true;

    // Iterate through the grid
    for (let i = 0; i < M; i++) {
        for (let j = 0; j < N; j++) {
            if (i === 0 && j === 0) continue;

            const G = grid[i][j];

            // Check paths coming from UP (i-1, j)
            if (i > 0) {
                for (let x = 0; x < MAX_XOR; x++) {
                    if (DP[i - 1][j][x]) {
                        const newXOR = x ^ G;
                        DP[i][j][newXOR] = true;
                    }
                }
            }

            // Check paths coming from LEFT (i, j-1)
            if (j > 0) {
                for (let y = 0; y < MAX_XOR; y++) {
                    if (DP[i][j - 1][y]) {
                        const newXOR = y ^ G;
                        DP[i][j][newXOR] = true;
                    }
                }
            }
        }
    }

    // Find the minimum achievable XOR sum at the destination (M-1, N-1)
    const finalDP = DP[M - 1][N - 1];
    for (let x = 0; x < MAX_XOR; x++) {
        if (finalDP[x]) {
            // Since we iterate upwards, the first true index is the minimum
            return x;
        }
    }

    // Should not be reached given problem constraints
    return -1; 
}

