function solve(grid: number[][]): number {
    const M = grid.length;
    if (M === 0) return 0;
    const N = grid[0].length;
    if (N === 0) return 0;

    // Since grid values are <= 1023 (2^10 - 1), we only need 1024 possible XOR sums.
    const MAX_XOR = 1024; 

    // DP[i][j] is an array of size MAX_XOR, where DP[i][j][k] is true 
    // if an XOR sum of k is achievable at (i, j).
    // We use boolean arrays for efficiency since the range is small.
    const DP: boolean[][][] = Array(M).fill(0).map(() => 
        Array(N).fill(0).map(() => 
            new Array(MAX_XOR).fill(false)
        )
    );

    // Base case: (0, 0)
    DP[0][0][grid[0][0]] = true;

    // Iterate through the grid in row-major order
    for (let i = 0; i < M; i++) {
        for (let j = 0; j < N; j++) {
            if (i === 0 && j === 0) continue;

            const currentValue = grid[i][j];

            // Calculate DP[i][j] based on predecessors

            // 1. From Up (i-1, j)
            if (i > 0) {
                for (let k = 0; k < MAX_XOR; k++) {
                    if (DP[i - 1][j][k]) {
                        const newXor = k ^ currentValue;
                        DP[i][j][newXor] = true;
                    }
                }
            }

            // 2. From Left (i, j-1)
            if (j > 0) {
                for (let k = 0; k < MAX_XOR; k++) {
                    if (DP[i][j - 1][k]) {
                        const newXor = k ^ currentValue;
                        DP[i][j][newXor] = true;
                    }
                }
            }
        }
    }

    // Find the minimum achievable XOR sum at the target (M-1, N-1)
    const finalRow = M - 1;
    const finalCol = N - 1;

    for (let k = 0; k < MAX_XOR; k++) {
        if (DP[finalRow][finalCol][k]) {
            return k;
        }
    }

    // Should be unreachable given problem constraints
    return -1; 
}
