function solve(grid: number[][]): number {
    const M = grid.length;
    if (M === 0) return 0;
    const N = grid[0].length;
    if (N === 0) return 0;

    // dp[i][j] stores a Set of all possible XOR sums achievable upon reaching (i, j).
    const dp: Set<number>[][] = Array(M).fill(0).map(() => Array(N).fill(null).map(() => new Set<number>()));

    // Base case (0, 0)
    dp[0][0].add(grid[0][0]);

    // Fill the DP table
    for (let i = 0; i < M; i++) {
        for (let j = 0; j < N; j++) {
            if (i === 0 && j === 0) {
                continue;
            }

            const currentValue = grid[i][j];
            const currentSet = dp[i][j];

            // 1. Coming from above (i-1, j)
            if (i > 0) {
                for (const xorSum of dp[i - 1][j]) {
                    currentSet.add(xorSum ^ currentValue);
                }
            }

            // 2. Coming from left (i, j-1)
            if (j > 0) {
                for (const xorSum of dp[i][j - 1]) {
                    currentSet.add(xorSum ^ currentValue);
                }
            }
        }
    }

    // Find the minimum XOR sum in dp[M-1][N-1]
    const finalSet = dp[M - 1][N - 1];

    if (finalSet.size === 0) {
        // Should not happen given constraints M>=1, N>=1
        return 0; 
    }

    let minXOR = 1024; // Max possible XOR sum is < 1024
    for (const xorSum of finalSet) {
        if (xorSum < minXOR) {
            minXOR = xorSum;
        }
    }

    return minXOR;
}

