    const M = grid.length;
    const N = grid[0].length;

    // DP[i][j] will store a Set of all possible XOR sums reaching cell (i, j)
    // Initialize DP table: M rows, N columns, each element being a Set<number>
    const dp: Set<number>[][] = Array(M).fill(null).map(() => Array(N).fill(null).map(() => new Set<number>()));

    // Base case: Starting cell (0, 0)
    dp[0][0].add(grid[0][0]);

    // Fill the DP table
    for (let i = 0; i < M; i++) {
        for (let j = 0; j < N; j++) {
            if (i === 0 && j === 0) {
                continue;
            }

            const currentValue = grid[i][j];
            const currentSet = dp[i][j];

            // 1. Check movement from above (i-1, j)
            if (i > 0) {
                const prevSet = dp[i - 1][j];
                for (const prevXor of prevSet) {
                    currentSet.add(prevXor ^ currentValue);
                }
            }

            // 2. Check movement from left (i, j-1)
            if (j > 0) {
                const prevSet = dp[i][j - 1];
                for (const prevXor of prevSet) {
                    currentSet.add(prevXor ^ currentValue);
                }
            }
        }
    }

    // The result is the minimum value in the set at the bottom-right corner
    const finalSet = dp[M - 1][N - 1];

    if (finalSet.size === 0) {
        // Should not happen given constraints, but handle defensively
        return -1; // Or throw error, but 0 is a possible answer
